  const game = new Game();
  window.game = game; // for debugging
  game.start();
});

/**
 * RevealSystem manages the reveal token economy and visibility maps.
 * Each player starts with 3 tokens. 1 token = 1 turn of revealing info.
 */
export class RevealSystem {
  constructor() {
    // Tokens per player
    this.tokens = { A: 3, B: 3 };
    // Which cells each player can see: { A: Set<'x,y'>, B: Set<'x,y'> }
    this.visible = {
      A: new Set(),
      B: new Set(),
    };
  }

reset() {
    this.tokens = { A: 3, B: 3 };
    this.visible.A.clear();
    this.visible.B.clear();
  }

/**
   * Compute initial visible cells based on player positions and "adjacent" range.
   * Player can see: their own cell + 4 orthogonally adjacent cells.
   */
  computeVisibility(player, px, py, grid) {
    const set = this.visible[player];
    set.add(`${px},${py}`);
    const adjacents = [
      [px, py - 1], [px, py + 1],
      [px - 1, py], [px + 1, py],
    ];
    for (const [ax, ay] of adjacents) {
      if (ax >= 0 && ax < grid.width && ay >= 0 && ay < grid.height) {
        set.add(`${ax},${ay}`);
      }
    }
  }

/**
   * Reveal a specific cell (using a token).
   * Returns the revealed data, or null if no tokens left.
   */
  revealCell(player, x, y, grid) {
    if (this.tokens[player] <= 0) return null;
    if (x < 0 || x >= grid.width || y < 0 || y >= grid.height) return null;

this.tokens[player]--;
    const key = `${x},${y}`;
    this.visible[player].add(key);

const cellData = grid.cells[y][x];
    return {
      x, y,
      entities: cellData,
      tokensLeft: this.tokens[player],
    };
  }

/**
   * Reveal a 3×3 area centered on (cx,cy). Costs 1 token.
   */
  revealArea(player, cx, cy, grid) {
    if (this.tokens[player] <= 0) return [];
    this.tokens[player]--;

const revealed = [];
    for (let dy = -1; dy <= 1; dy++) {
      for (let dx = -1; dx <= 1; dx++) {
        const nx = cx + dx;
        const ny = cy + dy;
        if (nx >= 0 && nx < grid.width && ny >= 0 && ny < grid.height) {
          const key = `${nx},${ny}`;
          if (!this.visible[player].has(key)) {
            this.visible[player].add(key);
            revealed.push({ x: nx, y: ny, entities: grid.cells[ny][nx] });
          }
        }
      }
    }
    return revealed;
  }
}

/**
 * MessageLog manages the shared message log in the UI.
 */
export class MessageLog {
  constructor(containerId) {
    this.container = document.getElementById(containerId);
    this.maxEntries = 50;
  }

add(message, type = 'system') {
    const entry = document.createElement('div');
    entry.className = `log-entry ${type}`;
    const time = new Date().toLocaleTimeString('zh-CN', {
      hour: '2-digit', minute: '2-digit', second: '2-digit'
    });
    entry.textContent = `[${time}] ${message}`;
    this.container.prepend(entry);

// Trim old entries
    while (this.container.children.length > this.maxEntries) {
      this.container.lastChild.remove();
    }
  }

addMove(playerName, directionName) {
    this.add(`${playerName} 向 ${directionName} 移动`, 'system');
  }

addReveal(playerName, what) {
    this.add(`${playerName} 揭示了：${what}`, 'reveal');
  }

addWait(playerName) {
    this.add(`${playerName} 等待`, 'system');
  }

addWin(message) {
    this.add(`🏆 ${message}`, 'win');
  }

clear() {
    this.container.innerHTML = '';
  }
}

const KEY_MAP_PLAYER_A = {
  ArrowUp:    DIRECTION.UP,
  ArrowDown:  DIRECTION.DOWN,
  ArrowLeft:  DIRECTION.LEFT,
  ArrowRight: DIRECTION.RIGHT,
  w: DIRECTION.UP,
  s: DIRECTION.DOWN,
  a: DIRECTION.LEFT,
  d: DIRECTION.RIGHT,
};

const KEY_MAP_PLAYER_B = {
  i: DIRECTION.UP,
  k: DIRECTION.DOWN,
  j: DIRECTION.LEFT,
  l: DIRECTION.RIGHT,
};

/**
 * InputHandler captures keyboard events and maps them to game actions.
 */
export class InputHandler {
  constructor(onMove, onReveal, onWait, onUndo) {
    this.onMove = onMove;     // (player, direction)
    this.onReveal = onReveal; // (player)
    this.onWait = onWait;     // (player)
    this.onUndo = onUndo;     // ()
    this._handler = this._handleKey.bind(this);
  }

attach() {
    window.addEventListener('keydown', this._handler);
  }

detach() {
    window.removeEventListener('keydown', this._handler);
  }

_handleKey(e) {
    // Don't capture if focus is in an input
    if (e.target.tagName === 'INPUT' || e.target.tagName === 'SELECT' ||
        e.target.tagName === 'TEXTAREA' || e.target.isContentEditable) return;

// Global undo
    if (e.ctrlKey && e.key === 'z') {
      e.preventDefault();
      this.onUndo();
      return;
    }

// Reveal actions
    if (e.key === 'q') {
      e.preventDefault();
      this.onReveal(PLAYER.A);
      return;
    }
    if (e.key === 'u') {
      e.preventDefault();
      this.onReveal(PLAYER.B);
      return;
    }

// Wait actions
    if (e.key === 'e') {
      e.preventDefault();
      this.onWait(PLAYER.A);
      return;
    }
    if (e.key === 'o') {
      e.preventDefault();
      this.onWait(PLAYER.B);
      return;
    }

// Movement
    const dirA = KEY_MAP_PLAYER_A[e.key];
    if (dirA !== undefined) {
      e.preventDefault();
      this.onMove(PLAYER.A, dirA);
      return;
    }

const dirB = KEY_MAP_PLAYER_B[e.key];
    if (dirB !== undefined) {
      e.preventDefault();
      this.onMove(PLAYER.B, dirB);
      return;
    }
  }
}

import { GameState } from '../game/GameState.js';
import { GameEngine } from '../game/GameEngine.js';
import { parseRules } from '../game/DSLParser.js';
import { BoardRenderer } from './BoardRenderer.js';
import { RevealSystem } from './RevealSystem.js';
import { InputHandler } from './InputHandler.js';
import { MessageLog } from './MessageLog.js';
import { PLAYER, DIRECTION } from '../game/constants.js';

const PLAYER_NAMES = { A: '🔵 玩家A', B: '🟠 玩家B' };
const DIR_NAMES = {
  [DIRECTION.UP]: '↑上',
  [DIRECTION.DOWN]: '↓下',
  [DIRECTION.LEFT]: '←左',
  [DIRECTION.RIGHT]: '→右',
};

export class Game {
  constructor() {
    this.state = null;
    this.engine = null;
    this.reveal = new RevealSystem();
    this.log = new MessageLog('message-log');

this.input = new InputHandler(
      (p, d) => this.handleMove(p, d),
      (p) => this.handleReveal(p),
      (p) => this.handleWait(p),
      () => this.handleUndo()
    );

// Bind cell click
    this.rendererA.onCellClick = (pos) => this.onCellClick('A', pos);
    this.rendererB.onCellClick = (pos) => this.onCellClick('B', pos);

// Bind buttons
    document.getElementById('btn-restart').addEventListener('click', () => this.restart());
    document.getElementById('map-select').addEventListener('change', (e) => {
      if (e.target.value) this.loadMap(e.target.value);
    });
  }

start() {
    this.loadMap('5x5-default');
    this.input.attach();
  }

loadMap(mapId) {
    const rulesEl = document.getElementById('rules-source');
    let rulesText = '';

// Try to load from a data attribute or embedded script
    const scriptEl = document.getElementById(`map-${mapId}`);
    if (scriptEl) {
      rulesText = scriptEl.textContent.trim();
    }

if (!rulesText) {
      // Fallback: generate a default ruleset for the map
      rulesText = this.getDefaultRules(mapId);
    }

const rules = parseRules(rulesText);
    if (!rules) {
      this.log.add('⚠️ 规则解析失败', 'system');
      return;
    }

this.state = new GameState(rules);
    this.engine = new GameEngine(this.state, rules);
    this.reveal.reset();

// Initialize visibility for both players
    this.reveal.computeVisibility('A', this.state.players.A.x, this.state.players.A.y, this.state.grid);
    this.reveal.computeVisibility('B', this.state.players.B.x, this.state.players.B.y, this.state.grid);

// Build grids
    this.rendererA.buildGrid();
    this.rendererB.buildGrid();

this.log.clear();
    this.log.add(`🗺️ 加载地图: ${mapId}`, 'system');
    this.log.add(`${PLAYER_NAMES.A} 起始位置: (${this.state.players.A.x}, ${this.state.players.A.y})`, 'system');
    this.log.add(`${PLAYER_NAMES.B} 起始位置: (${this.state.players.B.x}, ${this.state.players.B.y})`, 'system');
    this.log.add('提示：移动到相邻格可揭示周围信息；按 Q/E 揭示A玩家区域，U/O 揭示B玩家区域', 'system');
  }

getDefaultRules(mapId) {
    const [width, height] = mapId.split('-')[0].split('x').map(Number);
    // Generate simple rules: each player starts in corners, random win items placed
    return `# Default rules for ${mapId}
GRID ${width} ${height}
PLAYER_A_START 1 1
PLAYER_B_START ${width} ${height}
WIN_CONDITION COLLECT_TARGET
`;
  }

onCellClick(player, { x, y }) {
    // Reveal cell using a token
    const result = this.reveal.revealCell(player, x, y, this.state.grid);
    if (!result) {
      this.log.add(`${PLAYER_NAMES[player]} 没有揭示次数了`, 'system');
      return;
    }

this.selectedCell[player] = { x, y };
    const entities = result.entities;
    const desc = entities.length > 0
      ? entities.map(e => `${e.name}[${e.propertyName}]`).join(', ')
      : '空地';
    this.log.addReveal(PLAYER_NAMES[player], `(${x},${y}) → ${desc} (剩余${result.tokensLeft}次)`);
    this.updateUI();
  }

const result = this.engine.movePlayer(player, direction);
    if (!result.success) {
      this.log.add(`${PLAYER_NAMES[player]} ${result.reason}`, 'system');
      return;
    }

const { x, y } = this.state.players[player];
    this.reveal.computeVisibility(player, x, y, this.state.grid);
    this.log.addMove(PLAYER_NAMES[player], DIR_NAMES[direction]);

// Check for win
    if (result.gameOver) {
      this.onWin(result);
      return;
    }

const pos = this.state.players[player];
    const result = this.reveal.revealArea(player, pos.x, pos.y, this.state.grid);
    if (result.length === 0) {
      this.log.add(`${PLAYER_NAMES[player]} 没有揭示次数了`, 'system');
      return;
    }

const desc = result.map(r =>
      r.entities.length > 0
        ? r.entities.map(e => e.name).join('+')
        : '空地'
    ).join(', ');
    this.log.addReveal(PLAYER_NAMES[player], `周围: ${desc}`);
    this.updateUI();
  }

handleWait(player) {
    if (!this.state || this.state.gameOver) return;
    this.log.addWait(PLAYER_NAMES[player]);
    // Waiting does nothing mechanically, just passes turn insight
  }

handleUndo() {
    if (!this.state || !this.engine) return;
    const success = this.engine.undoLastMove();
    if (success) {
      this.log.add('↩️ 撤销上一步', 'system');
      // Recompute visibility
      this.reveal.computeVisibility('A', this.state.players.A.x, this.state.players.A.y, this.state.grid);
      this.reveal.computeVisibility('B', this.state.players.B.x, this.state.players.B.y, this.state.grid);
    } else {
      this.log.add('无可撤销步骤', 'system');
    }
    this.updateUI();
  }

onWin(result) {
    const playerName = PLAYER_NAMES[result.winner];
    this.log.addWin(`${playerName} 获胜！`);
    this.rendererA.showWinOverlay(`${playerName} 获胜！`);
    this.state.gameOver = true;
    this.updateUI();
  }

// Render both grids
    this.rendererA.render(this.reveal.visible.A, this.selectedCell.A || {});
    this.rendererB.render(this.reveal.visible.B, this.selectedCell.B || {});

// Update tokens display
    document.getElementById('reveal-tokens').textContent =
      `🔎 A:${this.reveal.tokens.A} B:${this.reveal.tokens.B}`;

// Update info panels
    const infoA = document.getElementById('info-a');
    const infoB = document.getElementById('info-b');
    if (infoA && this.state.players.A) {
      const pa = this.state.players.A;
      const cellData = this.state.grid.cells[pa.y][pa.x];
      const entities = cellData.map(e => `${e.icon} ${e.name}[${e.propertyName}]`).join(', ') || '空地';
      infoA.innerHTML = `
        <div class="current-turn">📍 位置: (${pa.x}, ${pa.y})</div>
        <div>当前位置: ${entities}</div>
        <div>揭示次数: ${this.reveal.tokens.A}</div>
      `;
    }
    if (infoB && this.state.players.B) {
      const pb = this.state.players.B;
      const cellData = this.state.grid.cells[pb.y][pb.x];
      const entities = cellData.map(e => `${e.icon} ${e.name}[${e.propertyName}]`).join(', ') || '空地';
      infoB.innerHTML = `
        <div class="current-turn">📍 位置: (${pb.x}, ${pb.y})</div>
        <div>当前位置: ${entities}</div>
        <div>揭示次数: ${this.reveal.tokens.B}</div>
      `;
    }

// Highlight active player view (both always active in this co-op/parallel exploration)
    document.getElementById('view-a').classList.toggle('active-turn', !this.state.gameOver);
    document.getElementById('view-b').classList.toggle('active-turn', !this.state.gameOver);
  }

restart() {
    this.loadMap(document.getElementById('map-select').value || '5x5-default');
  }
}

/**
 * BoardRenderer — renders the grid DOM for a specific player's perspective.
 * Each player sees only items they are "adjacent to" or have been revealed.
 */
export class BoardRenderer {
  constructor(playerViewId, stateAccessor) {
    this.container = document.getElementById(playerViewId);
    this.stateAccessor = stateAccessor; // () => GameState
    this.gridEl = null;
    this.onCellClick = null; // callback( { player, x, y } )
  }

buildGrid() {
    const state = this.stateAccessor();
    const grid = state.grid;
    this.gridEl = document.createElement('div');
    this.gridEl.className = 'grid';
    this.gridEl.style.gridTemplateColumns = `repeat(${grid.width}, 1fr)`;
    this.gridEl.style.gridTemplateRows = `repeat(${grid.height}, 1fr)`;

for (let y = 0; y < grid.height; y++) {
      for (let x = 0; x < grid.width; x++) {
        const cell = document.createElement('div');
        cell.className = 'grid-cell';
        cell.dataset.x = x;
        cell.dataset.y = y;
        cell.addEventListener('click', () => {
          if (this.onCellClick) {
            const pid = this.container.id === 'player-a-grid' ? 'A' : 'B';
            this.onCellClick({ player: pid, x, y });
          }
        });
        this.gridEl.appendChild(cell);
      }
    }

// Replace existing grid
    this.container.innerHTML = '';
    this.container.appendChild(this.gridEl);
  }

/**
   * Refresh cell contents based on current state and visibility map.
   * @param {Set<string>} visibleSet — keys like "x,y"
   * @param {{x?:number,y?:number}} selection
   */
  render(visibleSet, selection = {}) {
    const state = this.stateAccessor();
    const grid = state.grid;
    const cells = this.gridEl.querySelectorAll('.grid-cell');
    const pid = this.container.id === 'player-a-grid' ? 'A' : 'B';

cells.forEach(cell => {
      const x = parseInt(cell.dataset.x);
      const y = parseInt(cell.dataset.y);
      const key = `${x},${y}`;
      cell.innerHTML = '';

// Selection highlight
      cell.classList.toggle('selected',
        selection.x === x && selection.y === y);

// Hidden cell
      if (!visibleSet.has(key)) {
        cell.classList.add('hidden');
        cell.title = '未探索区域';
        return;
      }

cell.classList.remove('hidden');
      const cellData = grid.cells[y][x];
      cell.title = '';

// Render entities
      if (cellData.length === 0) {
        cell.innerHTML = '<span style="color:#333">·</span>';
        cell.title = '空地';
      } else {
        // Primary entity icon
        const entity = cellData[0];
        cell.innerHTML = `<span class="cell-icon">${entity.icon}</span>`;

// If multiple, show count
        if (cellData.length > 1) {
          const badge = document.createElement('span');
          badge.className = 'cell-rule-indicator';
          badge.textContent = `×${cellData.length}`;
          cell.appendChild(badge);
        }

// Build tooltip
        cell.title = cellData.map(e =>
          `${e.name} [${e.propertyName}]`
        ).join(', ');
      }
    });
  }

showWinOverlay(message) {
    // Remove previous overlay
    const prev = document.querySelector('.win-overlay');
    if (prev) prev.remove();

const overlay = document.createElement('div');
    overlay.className = 'win-overlay';
    overlay.innerHTML = `
      <div class="win-dialog">
        <h2>🎉 胜利！</h2>
        <p>${message}</p>
        <button id="win-restart">重新开始</button>
      </div>
    `;
    document.body.appendChild(overlay);

document.getElementById('win-restart').addEventListener('click', () => {
      overlay.remove();
      window.dispatchEvent(new CustomEvent('game-restart'));
    });
  }
}

